"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { SelectedRouteSummary } from "@/components/booking/SelectedRouteSummary";
import { RouteBreakdownPanel } from "@/components/planner/RouteBreakdownPanel";
import { PassengerForm, type PassengerFormData } from "@/components/booking/PassengerForm";
import { BookingSummaryCard } from "@/components/booking/BookingSummaryCard";
import { TicketPreviewCard } from "@/components/booking/TicketPreviewCard";
import { PaymentSection } from "@/components/booking/PaymentSection";
import {
  getPendingBooking,
  setPendingBooking,
  saveBooking,
  generateBookingId,
  clearPendingBooking,
  type BookingData,
} from "@/lib/bookings";
import type { RouteOption } from "@/components/planner/types";

export default function BookingPage() {
  const router = useRouter();
  const [pending, setPending] = useState<{
    route: RouteOption;
    source: string;
    destination: string;
  } | null>(null);
  const [formData, setFormData] = useState<PassengerFormData>({
    passengerName: "",
    email: "",
    phone: "",
    ticketCount: 1,
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const data = getPendingBooking();
    if (!data) {
      router.replace("/dashboard/planner");
      return;
    }
    setPending(data);
  }, [router]);

  if (!pending) return null;

  const { route, source, destination } = pending;
  const transport =
    route.legs.find((l) => l.mode !== "walk")?.mode ?? "walk";
  const transportLabel =
    transport.charAt(0).toUpperCase() + transport.slice(1);
  const totalCost = route.estimatedCost * formData.ticketCount;

  const handleConfirm = async (method: string) => {
    setIsSubmitting(true);
    const bookingId = generateBookingId();
    const booking: BookingData = {
      id: bookingId,
      route,
      source,
      destination,
      passengerName: formData.passengerName,
      email: formData.email,
      phone: formData.phone,
      ticketCount: formData.ticketCount,
      totalCost,
      bookingDate: new Date().toISOString(),
    };
    saveBooking(booking);
    clearPendingBooking();
    setIsSubmitting(false);
    router.push(`/dashboard/bookings/confirm?id=${bookingId}`);
  };

  return (
    <div className="space-y-6">
      <div>
        <Link
          href="/dashboard/planner"
          className="text-sm text-[#22C55E] hover:underline"
        >
          ← Back to Route Comparison
        </Link>
        <h1 className="font-sans text-2xl font-normal text-[#111111] mt-2">
          Book Route
        </h1>
        <p className="mt-1 text-[#6B6B6B] text-sm">
          Complete your booking details
        </p>
      </div>

      <SelectedRouteSummary
        route={route}
        source={source}
        destination={destination}
      />

      <RouteBreakdownPanel route={route} />

      <div className="grid gap-6 lg:grid-cols-[1fr_340px]">
        <div className="space-y-6">
          <PassengerForm data={formData} onChange={setFormData} />
          <TicketPreviewCard
            passengerName={formData.passengerName || "—"}
            source={source}
            destination={destination}
            transport={transportLabel}
            travelTime={route.totalTime}
            bookingId="—"
          />
          <PaymentSection onConfirm={handleConfirm} isLoading={isSubmitting} />
        </div>
        <div>
          <BookingSummaryCard
            source={source}
            destination={destination}
            transport={transportLabel}
            travelTime={route.totalTime}
            distance={route.totalDistance}
            ticketPrice={route.estimatedCost}
            ticketCount={formData.ticketCount}
          />
        </div>
      </div>
    </div>
  );
}
